function g(n,l,s,y,b){const c=n.reduce((t,r)=>t+r.quantity*r.unit_price,0),e=n.filter(t=>t.category==="labor").reduce((t,r)=>t+r.quantity*r.unit_price,0),u=n.filter(t=>t.category==="material").reduce((t,r)=>t+r.quantity*r.unit_price,0),o=n.filter(t=>t.category==="equipment").reduce((t,r)=>t+r.quantity*r.unit_price,0),i=c-e-u-o,a=e*l/100+u*s/100+o*y/100+i*.15,m=(c+a)*(b/100),f=c+a+m;return{subtotal:c,laborSub:e,matSub:u,eqSub:o,otherSub:i,marginAmount:a,taxAmount:m,total:f}}function p(n){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",minimumFractionDigits:2,maximumFractionDigits:2}).format(n)}export{g as c,p as f};
